import json
import logging
import re
import time

import requests

logger = logging.getLogger(__name__)

AGENT_ENDPOINT = "https://agent-prod.studio.lyzr.ai/v3/inference/chat/"

_PROMPT_TEMPLATE = """\
You are a knowledge base ingestion assistant.

You will receive a structured JSON document extracted from Confluence.

Your task:
1. Split the document into semantic chunks. Each chunk corresponds to one section or meaningful sub-section. Do NOT split mid-sentence or mid-table.
2. For each chunk generate 3-7 relevant topic tags (e.g. "eligibility", "healthcare", "claims", "dental", "vision").
3. Format each chunk_text as:
   Title: {{page_title}}

   Section: {{section_heading}}

   {{content text, tables formatted as markdown}}

4. Return ONLY a valid JSON object with NO additional commentary, no markdown fences:

{{
  "chunks": [
    {{
      "chunk_index": 0,
      "section_heading": "Section Name",
      "chunk_text": "Title: ...\\n\\nSection: ...\\n\\n...",
      "tags": ["tag1", "tag2"]
    }}
  ]
}}

Document JSON:
{document_json}
"""


class LyzrParseError(Exception):
    pass


class LyzrClient:
    def __init__(self, api_key: str, agent_id: str, user_id: str):
        self.api_key = api_key
        self.agent_id = agent_id
        self.user_id = user_id

    def get_chunks_and_tags(self, document: dict, session_id: str) -> list:
        message = _PROMPT_TEMPLATE.format(
            document_json=json.dumps(document, indent=2)
        )
        payload = {
            "user_id": self.user_id,
            "agent_id": self.agent_id,
            "session_id": session_id,
            "message": message,
        }
        headers = {
            "Content-Type": "application/json",
            "x-api-key": self.api_key,
        }

        response_text = self._post_with_retry(AGENT_ENDPOINT, headers, payload)
        return self._parse_agent_response(response_text)

    def _post_with_retry(self, url: str, headers: dict, payload: dict) -> str:
        for attempt in range(3):
            try:
                resp = requests.post(url, headers=headers, json=payload, timeout=120)
                if resp.status_code in (429, 500, 502, 503):
                    wait = 2 ** attempt
                    logger.warning("HTTP %s from Lyzr agent, retrying in %ss", resp.status_code, wait)
                    time.sleep(wait)
                    continue
                resp.raise_for_status()
                data = resp.json()
                # Lyzr wraps the model reply in a "response" field
                return data.get("response", data.get("message", str(data)))
            except requests.exceptions.RequestException as exc:
                if attempt == 2:
                    raise
                wait = 2 ** attempt
                logger.warning("Lyzr request error (%s), retrying in %ss", type(exc).__name__, wait)
                time.sleep(wait)
        raise RuntimeError("All retries exhausted for Lyzr agent call")

    def _parse_agent_response(self, response_text: str) -> list:
        text = response_text.strip()

        # strip markdown fences if the agent wraps output despite the instruction
        fence_match = re.search(r"```(?:json)?\s*([\s\S]+?)\s*```", text)
        if fence_match:
            text = fence_match.group(1).strip()

        try:
            data = json.loads(text)
        except json.JSONDecodeError as exc:
            logger.error("Lyzr agent returned non-JSON response: %s", response_text[:500])
            raise LyzrParseError(f"Agent response is not valid JSON: {exc}") from exc

        chunks = data.get("chunks")
        if not isinstance(chunks, list):
            raise LyzrParseError(f"Agent response missing 'chunks' list. Got keys: {list(data.keys())}")

        return chunks

